    [Parameter] public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
