@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;
    private bool isLoading = true;
    private string? errorMessage;

    private int totalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            result = await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        currentFilter = new(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

