@page "/catalog"
@namespace sv_de801881365a414f8596fbba4704f35c.Components.Pages.Catalog
@using sv_de801881365a414f8596fbba4704f35c
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    <!-- Sidebar Filters -->
    <div class="col-md-3">
        <CatalogFilters Categories="categories"
                        OnApply="HandleApplyFilters"
                        OnClear="HandleClearFilters" />
    </div>

    <!-- Main Content -->
    <div class="col-md-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="text-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
                <p class="mt-2 text-muted">Loading products…</p>
            </div>
        }
        else if (result is not null && result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found matching your criteria.
            </div>
        }
        else if (result is not null)
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="result.Page"
                            PageSize="result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="result.Page"
                               TotalPages="totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;
    private bool isLoading = true;
    private string? errorMessage;

    private int totalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            result = await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        currentFilter = new(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

